import { MakeLogicType, actions, kea, listeners, path, reducers } from 'kea'

import posthog from 'lib/posthog-typed'

/** Where the command menu open was initiated from, reported on the `command menu opened` event. */
export type CommandOpenSource =
    | 'keyboard-shortcut'
    | 'nav-search-button'
    | 'nav-search-bar'
    | 'nav-footer-hint'
    | 'nav-tools-row'
    | 'nav-panel-callout'
    | 'quickstart'

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface commandLogicValues {
    isCommandOpen: boolean
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface commandLogicActions {
    closeCommand: () => {
        value: true
    }
    openCommand: (source: CommandOpenSource) => {
        source: CommandOpenSource
    }
    toggleCommand: (source: CommandOpenSource) => {
        source: CommandOpenSource
    }
}

export type commandLogicType = MakeLogicType<commandLogicValues, commandLogicActions>

export const commandLogic = kea<commandLogicType>([
    path(['lib', 'components', 'Command', 'commandLogic']),
    actions({
        openCommand: (source: CommandOpenSource) => ({ source }),
        closeCommand: true,
        toggleCommand: (source: CommandOpenSource) => ({ source }),
    }),
    reducers({
        isCommandOpen: [
            false,
            {
                openCommand: () => true,
                closeCommand: () => false,
                toggleCommand: (state) => !state,
            },
        ],
    }),
    listeners(({ values }) => ({
        openCommand: ({ source }) => {
            posthog.capture('command menu opened', { source })
        },
        toggleCommand: ({ source }) => {
            if (values.isCommandOpen) {
                posthog.capture('command menu opened', { source })
            }
        },
    })),
])
